722	/* --- Top-level parser --- */
723	
724	/* Forward declaration */
725	int parse_proc(void);
726	
727	/* Parse a complete PL/SW program.
728	   Top-level constructs: DCL declarations and PROC definitions.
729	   Returns a PROGRAM node with all top-level items as children. */
730	int parse_program(void) {
731	    int prog = nd_alloc(NODE_PROGRAM);
732	    if (prog == NODE_NULL) {
733	        parse_error("node pool full");
734	        return NODE_NULL;
735	    }
736	
737	    while (!parse_err && cur_type != TOK_EOF) {
738	        int child = NODE_NULL;
739	
740	        if (cur_type == TOK_DCL || cur_type == TOK_DECLARE) {
741	            child = parse_dcl();
742	        } else if (cur_type == TOK_PROC) {
743	            child = parse_proc();
744	        } else {
745	            /* Skip label: NAME COLON before PROC */
746	            if (cur_type == TOK_IDENT) {
747	                /* Look ahead: could be LABEL: PROC */
748	                int nlen = str_len(cur_text);
749	                char *name = arena_alloc(nlen + 1);
750	                if (name) str_copy(name, cur_text);
751	                parse_advance();
752	                if (cur_type == TOK_COLON) {
753	                    parse_advance();
754	                    /* Now expect PROC */
755	                    if (cur_type == TOK_PROC) {
756	                        child = parse_proc();
757	                        /* Overwrite the PROC name with the label */
758	                        if (child != NODE_NULL) {
759	                            nd_name[child] = name;
760	                        }
761	                    } else {
762	                        parse_error("expected PROC after label");
763	                        break;
764	                    }
765	                } else {
766	                    parse_error("unexpected top-level token");
767	                    break;
768	                }
769	            } else {
770	                parse_error("unexpected top-level token");
771	                break;
772	            }
773	        }
774	
775	        if (child != NODE_NULL) {
776	            nd_append(prog, child);
777	        }
778	    }
779	
780	    return prog;
781	}
