783	/* --- Procedure parser --- */
784	
785	/* Parse a parameter: NAME TYPE
786	   Returns a PARAM node with name and type set. */
787	int parse_param(void) {
788	    int n;
789	    int nlen;
790	    char *name;
791	    int type;
792	
793	    if (!is_alpha(cur_text[0])) {
794	        parse_error("expected param name");
795	        return NODE_NULL;
796	    }
797	    nlen = str_len(cur_text);
798	    name = arena_alloc(nlen + 1);
799	    if (name) str_copy(name, cur_text);
800	    parse_advance();
801	
802	    type = parse_type();
803	
804	    n = nd_alloc(NODE_PARAM);
805	    if (n != NODE_NULL) {
806	        nd_name[n] = name;
807	        nd_type[n] = type;
808	    }
809	    return n;
810	}
811	
812	/* Parse PROC name(params) OPTIONS(...) RETURNS(type); body END;
813	   Syntax:
814	     PROC NAME;                           -- no params, no options
815	     PROC NAME(A INT, B PTR);             -- with params
816	     PROC NAME OPTIONS(FREESTANDING);     -- with options
817	     PROC NAME(A INT) RETURNS(INT);       -- with return type
818	     PROC NAME(A INT) OPTIONS(NAKED) RETURNS(BYTE); body END;
819	
820	   PROC node layout:
821	     nd_name  = procedure name
822	     nd_left  = first parameter (PARAM nodes linked via nd_next)
823	     nd_right = body (BLOCK node)
824	     nd_ival  = option flags (OPT_FREESTANDING | OPT_NAKED | OPT_LEAF)
825	     nd_stor  = return type (TYPE_ constant, TYPE_NONE if no RETURNS) */
826	int parse_proc(void) {
827	    int n;
