843	    /* Procedure name -- may be a keyword token (like INIT).
844	       In label syntax (LABEL: PROC ...) the name follows PROC
845	       only if the next token is an identifier/keyword name,
846	       not ( or OPTIONS or RETURNS or ; */
847	    name = 0;
848	    if (cur_type != TOK_LPAREN && cur_type != TOK_OPTIONS
